import 'package:local_auth/local_auth.dart';
import 'package:shared_preferences/shared_preferences.dart';

class AuthService {
  final LocalAuthentication _localAuthentication = LocalAuthentication();
  static const String _isAuthenticatedKey = 'isAuthenticated';
  static const String _mockPassword = 'password123'; // Example password

  Future<bool> canCheckBiometrics() async {
    return await _localAuthentication.canCheckBiometrics;
  }

  Future<List<BiometricType>> getAvailableBiometrics() async {
    return await _localAuthentication.getAvailableBiometrics();
  }

  Future<bool> authenticateWithBiometrics() async {
    bool didAuthenticate = false;
    try {
      didAuthenticate = await _localAuthentication.authenticate(
        localizedReason: 'Please authenticate to access your account',
        options: const AuthenticationOptions(
          stickyAuth: true,
          useErrorDialogs: true,
        ),
      );
    } catch (e) {
      return false;
    }

