    if (success) {
      await _saveAuthenticatedStatus(true);
    }
    return success;
  }

  Future<void> _saveAuthenticatedStatus(bool status) async {
    final SharedPreferences prefs = await SharedPreferences.getInstance();
    await prefs.setBool(_isAuthenticatedKey, status);
  }

  Future<bool> isAuthenticated() async {
    final SharedPreferences prefs = await SharedPreferences.getInstance();
    return prefs.getBool(_isAuthenticatedKey) ?? false;
  }

  Future<void> logout() async {
    await _saveAuthenticatedStatus(false);
