class LoginScreen extends StatefulWidget {
  const LoginScreen({super.key});

  @override
  State<LoginScreen> createState() => _LoginScreenState();
}

class _LoginScreenState extends State<LoginScreen> {
  final TextEditingController _passwordController = TextEditingController();
  bool _biometricsAvailable = false;
  List<BiometricType> _availableBiometrics = [];
  String _authMessage = '';
  bool _isAttemptingBiometrics = false;

  @override
  void initState() {
    super.initState();
    _checkBiometricsAndAuthenticate();
  }

  Future<void> _checkBiometricsAndAuthenticate() async {
    bool canCheckBiometrics = await AuthService().canCheckBiometrics();
    List<BiometricType> availableBiometrics = [];
    if (canCheckBiometrics) {
      availableBiometrics = await AuthService().getAvailableBiometrics();
    }

    if (mounted) {
      setState(() {
        _biometricsAvailable = canCheckBiometrics;
        _availableBiometrics = availableBiometrics;
      });
    }

    if (_biometricsAvailable && _availableBiometrics.isNotEmpty) {
      await _authenticateWithBiometrics();
    }
  }

  Future<void> _authenticateWithBiometrics() async {
    if (_isAttemptingBiometrics) return;

    if (mounted) {
      setState(() {
        _isAttemptingBiometrics = true;
        _authMessage = 'Attempting biometric authentication...';
      });
    }

    bool authenticated = await AuthService().authenticateWithBiometrics();

    if (mounted) {
      setState(() {
        _isAttemptingBiometrics = false;
      });
    }

    if (authenticated) {
      _navigateToHome();
    } else {
      if (mounted) {
        setState(() {
          _authMessage = 'Biometric authentication failed or cancelled. Please use password.';
        });
      }
    }
  }

  void _navigateToHome() {
    Navigator.of(context).pushReplacement(
      MaterialPageRoute(builder: (context) => const HomeScreen()),
    );
  }

  Future<void> _loginWithPassword() async {
    setState(() {
      _authMessage = 'Logging in...';
    });

    bool success = await AuthService().loginWithPassword(_passwordController.text);

    if (success) {
      _navigateToHome();
    } else {
      setState(() {
        _authMessage = 'Incorrect password.';
      });
    }
  }

  @override
  Widget build(BuildContext context) {
    return Scaffold(
      appBar: AppBar(
        title: const Text('Login'),
      ),
      body: Center(
        child: Padding(
          padding: const EdgeInsets.all(16.0),
          child: Column(
            mainAxisAlignment: MainAxisAlignment.center,
            children: <Widget>[
              if (_biometricsAvailable && _availableBiometrics.isNotEmpty && !_isAttemptingBiometrics)
                Column(
                  children: [
                    ElevatedButton.icon(
